可能原因：
1. props 包含新对象/函数引用
2. React.memo 未正确使用比较函数
3. children 每次重新创建
4. 使用了内联样式或对象字面量

修复：使用 useCallback、useMemo 稳定引用

```javascript
import React, { memo, useMemo, useCallback } from 'react';

const ChildComponent = memo(({ data, onClick }) => {
  console.log('Child rendered');
  return <div onClick={onClick}>{data.value}</div>;
});

const ParentComponent = ({ fetchData }) => {
  const [count, setCount] = useState(0);

  // 稳定对象引用
  const data = useMemo(() => ({ value: 'example' }), []);

  // 稳定函数引用
  const handleClick = useCallback(() => {
    console.log('clicked');
  }, []);

  // 自定义比较函数（可选）
  const areEqual = (prevProps, nextProps) => {
    return prevProps.data.value === nextProps.data.value;
  };

  const ChildWithCustomCompare = memo(ChildComponent, areEqual);

  return (
    <>
      <button onClick={() => setCount(c => c + 1)}>Update</button>
      <ChildComponent data={data} onClick={handleClick} />
    </>
  );
};
```

关键点：确保传递给子组件的 props 引用稳定。useCallback 稳定函数，useMemo 稳定对象/数组。
